1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const SURVIVAL_NEIGHBORS = [2, 3];
5	const REPRODUCTION_NEIGHBORS = 3;
6	const NEIGHBOR_OFFSETS = [
7	  [-1, -1], [-1, 0], [-1, 1],
8	  [0, -1],           [0, 1],
9	  [1, -1],  [1, 0],  [1, 1],
10	] as const;
11	
12	const isWithinBounds = (row: number, col: number, maxRows: number, maxCols: number): boolean =>
13	  row >= 0 && row < maxRows && col >= 0 && col < maxCols;
14	
15	const countAliveNeighbors = (isAlive: (r: number, c: number) => boolean): number => {
16	  let count = 0;
17	  for (const [dr, dc] of NEIGHBOR_OFFSETS) {
18	    if (isAlive(dr, dc)) {
19	      count++;
20	    }
21	  }
22	  return count;
23	};
24	
25	const countNeighbors = (grid: Grid, row: number, col: number): number => {
26	  if (grid.length === 0) {
27	    return 0;
28	  }
29	  const rows = grid.length;
30	  const cols = grid[0].length;
31	  return countAliveNeighbors((dr, dc) => {
32	    const r = row + dr;
33	    const c = col + dc;
34	    return isWithinBounds(r, c, rows, cols) && grid[r][c];
35	  });
36	};
37	
38	const shouldCellBeAlive = (isAlive: boolean, neighbors: number): boolean =>
39	  (isAlive && SURVIVAL_NEIGHBORS.includes(neighbors)) ||
40	  (!isAlive && neighbors === REPRODUCTION_NEIGHBORS);
41	
42	const countNeighborsSparse = (
43	  grid: Map<string, boolean>,
44	  row: number,
45	  col: number
46	): number => {
47	  return countAliveNeighbors((dr, dc) => {
48	    const key = `${row + dr},${col + dc}`;
49	    return grid.get(key) ?? false;
50	  });
51	};
52	
53	export const nextGeneration = (grid: Grid): Grid => {
54	  if (grid.length === 0) {
55	    return [];
56	  }
57	
58	  return grid.map((row, rowIdx) =>
59	    row.map((cell, colIdx) => {
60	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
61	      return shouldCellBeAlive(cell, neighbors);
62	    })
63	  );
64	};
65	
66	export const nextGenerationSparse = (
67	  grid: Map<string, boolean>
68	): Map<string, boolean> => {
69	  const result = new Map<string, boolean>();
70	
71	  for (const [key] of grid) {
72	    const [row, col] = key.split(",").map(Number);
73	    const isAlive = grid.get(key) || false;
74	    const neighbors = countNeighborsSparse(grid, row, col);
75	    result.set(key, shouldCellBeAlive(isAlive, neighbors));
76	  }
77	
78	  return result;
79	};
